### Phase 2: Performance-Critical Code Patterns

#### 2.3 Panic-Free Error Handling Pattern

```rust
// src/lib.rs - Central error types
use thiserror::Error;

#[derive(Error, Debug)]
pub enum ProxyError {
    #[error("Cache lookup failed: {0}")]
    CacheLookup(String),

    #[error("Upstream connection failed: {0}")]
    UpstreamConnection(String),

    #[error("HLS parse error: {0}")]
    HlsParse(String),

    #[error("GCS error: {0}")]
    Gcs(String),

    #[error("Configuration error: {0}")]
    Config(String),
}

// NEVER use unwrap() - always propagate errors
pub type Result<T> = std::result::Result<T, ProxyError>;

// Pattern: Use Option::ok_or_else for conversions
fn get_content_length(headers: &HeaderMap) -> Result<usize> {
    headers
        .get(CONTENT_LENGTH)
        .ok_or_else(|| ProxyError::HlsParse("Missing Content-Length".into()))?
        .to_str()
        .map_err(|e| ProxyError::HlsParse(format!("Invalid header: {}", e)))?
        .parse()
        .map_err(|e| ProxyError::HlsParse(format!("Invalid length: {}", e)))
}
