#### 2.4 TinyUfo Cache Configuration for HLS

```rust
// src/cache/tinyufo.rs
use pingora_cache::{CacheKey, CachePhase, CachePut, HttpCache};
use pingora::prelude::*;
use std::time::Duration;

/// Cache configuration optimized for HLS streaming
pub struct HlsCacheConfig {
    /// Total cache size in bytes (default: 32GB for 4K content)
    pub max_size_bytes: usize,

    /// Segment TTL - HLS segments are immutable once created
    pub segment_ttl: Duration,

    /// Playlist TTL - Lower for live, higher for VOD
    pub playlist_ttl_live: Duration,
    pub playlist_ttl_vod: Duration,

    /// TinyUfo window size for admission frequency tracking
    pub tinyufo_window_size: usize,

    /// Number of samples for frequency estimation
    pub tinyufo_samples: usize,
}

impl Default for HlsCacheConfig {
    fn default() -> Self {
        Self {
            max_size_bytes: 32 * 1024 * 1024 * 1024, // 32GB
            segment_ttl: Duration::from_secs(86400 * 7), // 7 days for segments
            playlist_ttl_live: Duration::from_secs(2),   // 2s for live manifest
            playlist_ttl_vod: Duration::from_secs(3600), // 1 hour for VOD manifest
            tinyufo_window_size: 1000,
            tinyufo_samples: 100,
        }
    }
}

/// Cache key generation for HLS content
pub fn generate_cache_key(uri: &str, variant: Option<&str>) -> CacheKey {
    // Format: /content/{content_id}/{resolution}/{segment_or_playlist}
    // Example: /content/abc123/1080p/segment_001.ts
    let mut key = CacheKey::new(uri.to_string());

    if let Some(v) = variant {
        // Include variant (resolution/bitrate) in key for ABR
        key = key.with_variant(v);
    }

    key
}

/// Determine TTL based on content type
pub fn get_ttl_for_path(path: &str, is_live: bool) -> Duration {
    if path.ends_with(".m3u8") {
        if is_live {
            Duration::from_secs(2)
        } else {
            Duration::from_secs(3600)
        }
    } else if path.ends_with(".ts") || path.ends_with(".m4s") {
        // Video segments - immutable, cache long
        Duration::from_secs(86400 * 7)
    } else {
        // Default for unknown content
        Duration::from_secs(300)
    }
}
