#### 2.5 Cache Stampede Protection

```rust
// src/cache/stampede.rs
use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::{Mutex, broadcast};
use tokio::time::{timeout, Duration};

/// Prevents cache stampede using single-flight pattern with lock timeout
pub struct StampedeProtection {
    /// In-flight requests - key is cache key, value is broadcast sender
    in_flight: Arc<Mutex<HashMap<String, broadcast::Sender<Result<Vec<u8>, String>>>>>,

    /// Maximum time to wait for an in-flight request
    lock_timeout: Duration,

    /// Maximum concurrent in-flight requests per key
    max_waiters: usize,
}

impl StampedeProtection {
    pub fn new(lock_timeout_ms: u64, max_waiters: usize) -> Self {
        Self {
            in_flight: Arc::new(Mutex::new(HashMap::new())),
            lock_timeout: Duration::from_millis(lock_timeout_ms),
            max_waiters,
        }
    }

    /// Returns (should_fetch, optional_receiver)
    /// If should_fetch is true, this request should fetch from origin
    /// If should_fetch is false, wait on the receiver for the result
    pub async fn acquire(&self, key: &str) -> (bool, Option<broadcast::Receiver<Result<Vec<u8>, String>>>) {
        let mut in_flight = self.in_flight.lock().await;

        if let Some(sender) = in_flight.get(key) {
            // Another request is already fetching this key
            if sender.receiver_count() < self.max_waiters {
                return (false, Some(sender.subscribe()));
            }
            // Too many waiters, let this request through (degrade gracefully)
        }

        // This request will fetch from origin
        let (tx, _) = broadcast::channel(1);
        in_flight.insert(key.to_string(), tx);
        (true, None)
    }

    /// Signal completion to all waiters
    pub async fn complete(&self, key: &str, result: Result<Vec<u8>, String>) {
        let mut in_flight = self.in_flight.lock().await;
        if let Some(sender) = in_flight.remove(key) {
            // Ignore send error - receivers may have dropped
            let _ = sender.send(result);
        }
    }

    /// Wait for result with timeout
    pub async fn wait_for_result(
        &self,
        mut receiver: broadcast::Receiver<Result<Vec<u8>, String>>
    ) -> Option<Result<Vec<u8>, String>> {
        match timeout(self.lock_timeout, receiver.recv()).await {
            Ok(Ok(result)) => Some(result),
            Ok(Err(_)) => None, // Channel closed
            Err(_) => None,     // Timeout
        }
    }
}
