#### 2.6 Zero-Copy Serving with Sendfile

```rust
// src/app.rs - Main proxy implementation
use pingora::prelude::*;
use pingora_proxy::{ProxyHttp, Session};
use bytes::Bytes;
use std::os::unix::io::AsRawFd;

pub struct MediaEdgeProxy {
    cache: Arc<HlsCache>,
    stampede: Arc<StampedeProtection>,
    gcs_pool: Arc<GcsConnectionPool>,
    metrics: Arc<ProxyMetrics>,
}

#[async_trait]
impl ProxyHttp for MediaEdgeProxy {
    type CTX = RequestContext;

    fn new_ctx(&self) -> Self::CTX {
        RequestContext::new()
    }

    async fn request_filter(
        &self,
        session: &mut Session,
        ctx: &mut Self::CTX,
    ) -> Result<bool> {
        let path = session.req_header().uri.path();

        // Record request start for latency metrics
        ctx.start_time = std::time::Instant::now();

        // Parse HLS request
        ctx.is_segment = path.ends_with(".ts") || path.ends_with(".m4s");
        ctx.is_playlist = path.ends_with(".m3u8");

        // Extract content ID and resolution from path
        // Expected format: /v1/stream/{content_id}/{resolution}/...
        if let Some(parsed) = parse_hls_path(path) {
            ctx.content_id = Some(parsed.content_id);
            ctx.resolution = Some(parsed.resolution);
        }

        Ok(false) // Continue processing
    }

    async fn upstream_peer(
        &self,
        session: &mut Session,
        ctx: &mut Self::CTX,
    ) -> Result<Box<HttpPeer>> {
        // Check cache first
        let cache_key = generate_cache_key(
            session.req_header().uri.path(),
            ctx.resolution.as_deref()
        );

        if let Some(cached) = self.cache.get(&cache_key).await {
            ctx.cache_hit = true;
            self.metrics.cache_hits.inc();

            // Return cached response via zero-copy path
            return Ok(Box::new(CachedPeer::new(cached)));
        }

        ctx.cache_hit = false;
        self.metrics.cache_misses.inc();

        // Cache miss - check for stampede protection
        let (should_fetch, receiver) = self.stampede.acquire(&cache_key.to_string()).await;

        if !should_fetch {
            // Wait for another request to complete
            if let Some(rx) = receiver {
                if let Some(Ok(data)) = self.stampede.wait_for_result(rx).await {
                    // Got data from another request
                    ctx.cache_hit = true;
                    return Ok(Box::new(CachedPeer::new(Bytes::from(data))));
                }
            }
            // Fallthrough: timeout or error, fetch ourselves
        }

        ctx.stampede_leader = should_fetch;

        // Return GCS upstream peer from connection pool
        let peer = self.gcs_pool
            .get_peer()
            .await
            .map_err(|e| ProxyError::UpstreamConnection(e.to_string()))?;

        Ok(Box::new(peer))
    }

    async fn response_filter(
        &self,
        session: &mut Session,
        upstream_response: &mut ResponseHeader,
        ctx: &mut Self::CTX,
    ) -> Result<()> {
        // Add edge-specific headers
        upstream_response.insert_header(
            "X-Edge-Cache",
            if ctx.cache_hit { "HIT" } else { "MISS" }
        )?;

        upstream_response.insert_header(
            "X-Edge-Pop",
            &self.config.pop_id
        )?;

        // Record latency
        let latency = ctx.start_time.elapsed();
        self.metrics.request_latency.observe(latency.as_secs_f64());

        Ok(())
    }

    async fn upstream_response_body_filter(
        &self,
        session: &mut Session,
        body: &mut Option<Bytes>,
        end_of_stream: bool,
        ctx: &mut Self::CTX,
    ) -> Result<()> {
        // Accumulate body for caching
        if let Some(data) = body {
            ctx.response_body.extend_from_slice(data);
        }

        // When response complete, cache it
        if end_of_stream && !ctx.cache_hit {
            let cache_key = generate_cache_key(
                session.req_header().uri.path(),
                ctx.resolution.as_deref()
            );

            let ttl = get_ttl_for_path(
                session.req_header().uri.path(),
                ctx.is_live.unwrap_or(false)
            );

            // Cache the response
            self.cache.put(
                &cache_key,
                ctx.response_body.clone(),
                ttl
            ).await;

            // Signal stampede waiters
            if ctx.stampede_leader {
                self.stampede.complete(
                    &cache_key.to_string(),
                    Ok(ctx.response_body.to_vec())
                ).await;
            }
        }

        Ok(())
    }
}
