#### 2.7 GCS Connection Pool

```rust
// src/upstream/gcs_connector.rs
use hyper::client::conn::http2;
use hyper_util::rt::TokioExecutor;
use std::sync::atomic::{AtomicUsize, Ordering};
use tokio::sync::Semaphore;

pub struct GcsConnectionPool {
    /// GCS endpoint
    endpoint: String,

    /// Project ID for authentication
    project_id: String,

    /// Maximum connections per pool
    max_connections: usize,

    /// Connection semaphore for limiting concurrent connections
    semaphore: Arc<Semaphore>,

    /// Active connection count
    active_connections: AtomicUsize,

    /// HTTP/2 client for connection reuse
    client: Arc<hyper::Client<hyper_tls::HttpsConnector<hyper::client::HttpConnector>>>,
}

impl GcsConnectionPool {
    pub fn new(config: &GcsConfig) -> Self {
        // Configure connection pool with keep-alive
        let mut http_connector = hyper::client::HttpConnector::new();
        http_connector.set_keepalive(Some(Duration::from_secs(90)));
        http_connector.set_nodelay(true);
        http_connector.enforce_http(false);

        let https_connector = hyper_tls::HttpsConnector::new_with_connector(http_connector);

        let client = hyper::Client::builder()
            .http2_only(true)  // GCS supports HTTP/2
            .pool_max_idle_per_host(config.max_idle_connections)
            .pool_idle_timeout(Duration::from_secs(90))
            .build(https_connector);

        Self {
            endpoint: config.endpoint.clone(),
            project_id: config.project_id.clone(),
            max_connections: config.max_connections,
            semaphore: Arc::new(Semaphore::new(config.max_connections)),
            active_connections: AtomicUsize::new(0),
            client: Arc::new(client),
        }
    }

    pub async fn get_peer(&self) -> Result<GcsPeer> {
        // Acquire semaphore permit (with timeout)
        let permit = tokio::time::timeout(
            Duration::from_secs(5),
            self.semaphore.clone().acquire_owned()
        )
        .await
        .map_err(|_| ProxyError::UpstreamConnection("Connection pool timeout".into()))?
        .map_err(|_| ProxyError::UpstreamConnection("Semaphore closed".into()))?;

        self.active_connections.fetch_add(1, Ordering::SeqCst);

        Ok(GcsPeer {
            client: self.client.clone(),
            endpoint: self.endpoint.clone(),
            _permit: permit,
            active_counter: self.active_connections.clone(),
        })
    }
}

pub struct GcsPeer {
    client: Arc<hyper::Client<hyper_tls::HttpsConnector<hyper::client::HttpConnector>>>,
    endpoint: String,
    _permit: tokio::sync::OwnedSemaphorePermit,
    active_counter: Arc<AtomicUsize>,
}

impl Drop for GcsPeer {
    fn drop(&mut self) {
        self.active_counter.fetch_sub(1, Ordering::SeqCst);
    }
}
