### Phase 3: Graceful Shutdown (Lame Duck Mode)

#### 2.8 K8s-Compatible Graceful Shutdown

```rust
// src/shutdown.rs
use pingora::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicU64, Ordering};
use tokio::sync::watch;

/// Graceful shutdown state machine
#[derive(Clone, Copy, Debug, PartialEq)]
pub enum ShutdownState {
    /// Normal operation
    Running,
    /// Received SIGTERM, draining connections (lame duck)
    Draining,
    /// All connections drained, shutting down
    Terminated,
}

pub struct GracefulShutdown {
    /// Current state
    state: Arc<AtomicU8>,

    /// Active request counter
    active_requests: AtomicU64,

    /// Shutdown signal sender/receiver
    shutdown_tx: watch::Sender<ShutdownState>,
    shutdown_rx: watch::Receiver<ShutdownState>,

    /// Drain timeout (from K8s terminationGracePeriodSeconds)
    drain_timeout: Duration,

    /// Health check response during drain
    health_during_drain: bool,
}

impl GracefulShutdown {
    pub fn new(drain_timeout_secs: u64) -> Self {
        let (tx, rx) = watch::channel(ShutdownState::Running);

        Self {
            state: Arc::new(AtomicU8::new(0)), // 0 = Running
            active_requests: AtomicU64::new(0),
            shutdown_tx: tx,
            shutdown_rx: rx,
            drain_timeout: Duration::from_secs(drain_timeout_secs),
            health_during_drain: false, // Return unhealthy during drain
        }
    }

    /// Register signal handlers for graceful shutdown
    pub async fn register_signals(&self) -> Result<()> {
        let state = self.state.clone();
        let tx = self.shutdown_tx.clone();

        tokio::spawn(async move {
            let mut sigterm = tokio::signal::unix::signal(
                tokio::signal::unix::SignalKind::terminate()
            ).expect("Failed to register SIGTERM handler");

            let mut sigint = tokio::signal::unix::signal(
                tokio::signal::unix::SignalKind::interrupt()
            ).expect("Failed to register SIGINT handler");

            tokio::select! {
                _ = sigterm.recv() => {
                    tracing::info!("Received SIGTERM, entering lame duck mode");
                }
                _ = sigint.recv() => {
                    tracing::info!("Received SIGINT, entering lame duck mode");
                }
            }

            // Transition to draining
            state.store(1, Ordering::SeqCst);
            let _ = tx.send(ShutdownState::Draining);
        });

        Ok(())
    }

    /// Increment active request count
    pub fn request_start(&self) {
        self.active_requests.fetch_add(1, Ordering::SeqCst);
    }

    /// Decrement active request count
    pub fn request_end(&self) {
        let prev = self.active_requests.fetch_sub(1, Ordering::SeqCst);

        // Check if we're draining and this was the last request
        if prev == 1 && self.state.load(Ordering::SeqCst) == 1 {
            self.state.store(2, Ordering::SeqCst);
            let _ = self.shutdown_tx.send(ShutdownState::Terminated);
        }
    }

    /// Wait for shutdown with timeout
    pub async fn wait_for_shutdown(&self) {
        let mut rx = self.shutdown_rx.clone();

        // Wait for draining state
        while *rx.borrow() == ShutdownState::Running {
            if rx.changed().await.is_err() {
                break;
            }
        }

        tracing::info!(
            "Draining {} active requests",
            self.active_requests.load(Ordering::SeqCst)
        );

        // Wait for all requests to complete or timeout
        let drain_start = std::time::Instant::now();
        while *rx.borrow() == ShutdownState::Draining {
            if drain_start.elapsed() > self.drain_timeout {
                tracing::warn!("Drain timeout exceeded, forcing shutdown");
                break;
            }

            tokio::time::sleep(Duration::from_millis(100)).await;
        }

        tracing::info!("Shutdown complete");
    }

    /// Health check response (for K8s readiness probe)
    pub fn is_healthy(&self) -> bool {
        self.state.load(Ordering::SeqCst) == 0
    }
}
