        "media_edge_stampede_timeouts_total",
        "Stampede protection lock timeouts"
    ).expect("metric creation failed");

    // Active streams gauge
    pub static ref ACTIVE_STREAMS: Gauge = Gauge::new(
        "media_edge_active_streams",
        "Current active streaming sessions"
    ).expect("metric creation failed");
}

pub fn register_metrics() {
    REGISTRY.register(Box::new(HTTP_REQUESTS_TOTAL.clone())).unwrap();
    REGISTRY.register(Box::new(HTTP_REQUEST_DURATION.clone())).unwrap();
    REGISTRY.register(Box::new(CACHE_HITS.clone())).unwrap();
    REGISTRY.register(Box::new(CACHE_MISSES.clone())).unwrap();
    REGISTRY.register(Box::new(CACHE_SIZE_BYTES.clone())).unwrap();
    REGISTRY.register(Box::new(CACHE_EVICTIONS.clone())).unwrap();
    REGISTRY.register(Box::new(UPSTREAM_CONNECTIONS_ACTIVE.clone())).unwrap();
    REGISTRY.register(Box::new(UPSTREAM_CONNECTIONS_IDLE.clone())).unwrap();
    REGISTRY.register(Box::new(SEGMENTS_SERVED.clone())).unwrap();
    REGISTRY.register(Box::new(BYTES_SERVED.clone())).unwrap();
    REGISTRY.register(Box::new(STAMPEDE_COALESCED.clone())).unwrap();
    REGISTRY.register(Box::new(STAMPEDE_TIMEOUTS.clone())).unwrap();
    REGISTRY.register(Box::new(ACTIVE_STREAMS.clone())).unwrap();
}

/// Metrics endpoint handler
pub async fn metrics_handler() -> Result<String, String> {
    let encoder = TextEncoder::new();
    let metric_families = REGISTRY.gather();

    encoder
        .encode_to_string(&metric_families)
        .map_err(|e| format!("Encoding error: {}", e))
}
