          limits:
            memory: "16Gi"
            cpu: "4000m"
            ephemeral-storage: "50Gi"

        # Readiness probe - fails during drain
        readinessProbe:
          httpGet:
            path: /ready
            port: http
          initialDelaySeconds: 5
          periodSeconds: 5
          timeoutSeconds: 2
          failureThreshold: 2

        # Liveness probe - always healthy unless crashed
